var accountBalanceAfterPurchase = function(purchaseAmount) {
    const rem = purchaseAmount % 10;
    let rounded;
    if (rem < 5) {
        rounded = purchaseAmount - rem;
    } else {
        rounded = purchaseAmount + (10 - rem);
    }
    return 100 - rounded;
};
